{"code":"from hermes_tools import terminal, write_file
import json, os

BASE='QPzQbdDZLasm2vsqeFql0RPsgyg'
TABLE='tblBCgxj19VHYKFE'
VIEW='vewlIX1kHp'
NAME_FIELD='fldLDMChLn'
LEAVE_FIELD='fldn3wsdBf'
ID_FIELD='fldHYprdxt'
DATE_FIELDS=['26/4','27/4','30/4','1/5','2/5','3/5']

def run(cmd):
    r=terminal(cmd, timeout=240)
    if r['exit_code']!=0:
        raise RuntimeError(f"Command failed: {cmd}\n{r['output']}")
    return json.loads(r['output'])

# 1) Load full employee list and existing records
opts1=run(f"lark-cli base +field-search-options --as user --base-token {BASE} --table-id {TABLE} --field-id {NAME_FIELD} --offset 0 --limit 30")
opts2=run(f"lark-cli base +field-search-options --as user --base-token {BASE} --table-id {TABLE} --field-id {NAME_FIELD} --offset 30 --limit 30")
recs=run(f"lark-cli base +record-list --as user --base-token {BASE} --table-id {TABLE} --limit 200")

employees=[o['name'] for o in opts1['data']['options']] + [o['name'] for o in opts2['data']['options']]
existing_rows=[]
for rid,row in zip(recs['data']['record_id_list'], recs['data']['data']):
    # row = [ID, [name], [dates]]
    name=(row[1][0] if row[1] else None)
    dates=list(row[2] or [])
    existing_rows.append({'record_id':rid,'name':name,'dates':dates})

# 2) Create checkbox fields if absent
fields=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
existing_field_names={f['name'] for f in fields['data']['fields']}
created_field_ids={}
for d in DATE_FIELDS:
    if d not in existing_field_names:
        payload=json.dumps({'name': d, 'type': 'checkbox'}, ensure_ascii=False)
        res=run(f"lark-cli base +field-create --as user --base-token {BASE} --table-id {TABLE} --json {json.dumps(payload, ensure_ascii=False)}")
        fld=res['data']['field']
        created_field_ids[d]=fld['id'] if isinstance(fld, dict) and 'id' in fld else None

# Reload fields for exact IDs/order
fields=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
field_map={f['name']:f['id'] for f in fields['data']['fields']}

# 3) Update existing rows to checkbox format
for item in existing_rows:
    patch_obj={d: (d in item['dates']) for d in DATE_FIELDS}
    payload=json.dumps(patch_obj, ensure_ascii=False)
    run(f"lark-cli base +record-upsert --as user --base-token {BASE} --table-id {TABLE} --record-id {item['record_id']} --json {json.dumps(payload, ensure_ascii=False)}")

# 4) Create missing employee rows
existing_names={r['name'] for r in existing_rows if r['name']}
missing=[name for name in employees if name not in existing_names]
if missing:
    rows=[]
    for name in missing:
        rows.append([name] + [False]*len(DATE_FIELDS))
    batch={'fields':['Họ và tên'] + DATE_FIELDS,'rows':rows}
    p='/tmp/lark_base_batch_create.json'
    write_file(p, json.dumps(batch, ensure_ascii=False))
    run(f"lark-cli base +record-batch-create --as user --base-token {BASE} --table-id {TABLE} --json @{p}")

# 5) Reorder visible fields in grid view
visible={'visible_fields':['Họ và tên'] + DATE_FIELDS}
p='/tmp/lark_base_visible_fields.json'
write_file(p, json.dumps(visible, ensure_ascii=False))
run(f"lark-cli base +view-set-visible-fields --as user --base-token {BASE} --table-id {TABLE} --view-id {VIEW} --json @{p}")

# 6) Delete old fields from table schema if still present
# Delete multi-select leave field and auto-number field to match requested 7 columns.
for fid in [LEAVE_FIELD, ID_FIELD]:
    # only delete if still exists
    fields_now=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
    ids={f['id'] for f in fields_now['data']['fields']}
    if fid in ids:
        run(f"lark-cli base +field-delete --as user --base-token {BASE} --table-id {TABLE} --field-id {fid} --yes")

# 7) Final verification + counts
final_fields=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
final_records=run(f"lark-cli base +record-list --as user --base-token {BASE} --table-id {TABLE} --limit 200")
leave_counts={d:0 for d in DATE_FIELDS}
for row in final_records['data']['data']:
    # row now should be [name, bool...]
    name=row[0]
    for idx,d in enumerate(DATE_FIELDS, start=1):
        val=row[idx] if idx < len(row) else False
        if val is True:
            leave_counts[d]+=1

total_employees=len(employees)
work_counts={d: total_employees - leave_counts[d] for d in DATE_FIELDS}

print(json.dumps({
    'employees_total': total_employees,
    'existing_records_before': len(existing_rows),
    'created_missing_records': len(missing),
    'leave_counts': leave_counts,
    'work_counts': work_counts,
    'final_fields': [f['name'] for f in final_fields['data']['fields']],
    'final_record_total': len(final_records['data']['record_id_list'])
}, ensure_ascii=False, indent=2))"}

