{"code":"from hermes_tools import terminal, write_file
import json, os

BASE='QPzQbdDZLasm2vsqeFql0RPsgyg'
TABLE='tblBCgxj19VHYKFE'
VIEW='vewlIX1kHp'
NAME_FIELD='fldLDMChLn'
LEAVE_FIELD='fldn3wsdBf'
ID_FIELD='fldHYprdxt'
DATE_FIELDS=['26/4','27/4','30/4','1/5','2/5','3/5']
WORKDIR='/root'


def run(cmd, timeout=240):
    r=terminal(cmd, timeout=timeout, workdir=WORKDIR)
    if r['exit_code']!=0:
        raise RuntimeError(f"FAILED: {cmd}\n{r['output']}")
    return json.loads(r['output'])

# load employee master list
opts1=run(f"lark-cli base +field-search-options --as user --base-token {BASE} --table-id {TABLE} --field-id {NAME_FIELD} --offset 0 --limit 30")
opts2=run(f"lark-cli base +field-search-options --as user --base-token {BASE} --table-id {TABLE} --field-id {NAME_FIELD} --offset 30 --limit 30")
employees=[o['name'] for o in opts1['data']['options']] + [o['name'] for o in opts2['data']['options']]

# find existing names
recs=run(f"lark-cli base +record-list --as user --base-token {BASE} --table-id {TABLE} --limit 200")
existing_names=[]
for row in recs['data']['data']:
    for cell in row:
        if isinstance(cell, list) and len(cell)==1 and isinstance(cell[0], str) and cell[0] in employees:
            existing_names.append(cell[0])
            break
existing=set(existing_names)
missing=[n for n in employees if n not in existing]

# batch create missing rows with all date checkboxes false
if missing:
    batch={'fields':['Họ và tên']+DATE_FIELDS, 'rows': [[n, False, False, False, False, False, False] for n in missing]}
    write_file('/root/lark_base_batch_create.json', json.dumps(batch, ensure_ascii=False))
    run(f"lark-cli base +record-batch-create --as user --base-token {BASE} --table-id {TABLE} --json @./lark_base_batch_create.json")

# set grid visible field order
visible={'visible_fields':['Họ và tên']+DATE_FIELDS}
write_file('/root/lark_base_visible_fields.json', json.dumps(visible, ensure_ascii=False))
run(f"lark-cli base +view-set-visible-fields --as user --base-token {BASE} --table-id {TABLE} --view-id {VIEW} --json @./lark_base_visible_fields.json")

# delete old fields to match requested shape
fields=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
ids={f['id'] for f in fields['data']['fields']}
for fid in [LEAVE_FIELD, ID_FIELD]:
    if fid in ids:
        run(f"lark-cli base +field-delete --as user --base-token {BASE} --table-id {TABLE} --field-id {fid} --yes")

# verify final state
final_fields=run(f"lark-cli base +field-list --as user --base-token {BASE} --table-id {TABLE}")
final_records=run(f"lark-cli base +record-list --as user --base-token {BASE} --table-id {TABLE} --limit 200")
field_order=final_records['data']['fields']
leave_counts={d:0 for d in DATE_FIELDS}
name_count=0
for row in final_records['data']['data']:
    name_count += 1
    rowmap=dict(zip(field_order, row))
    for d in DATE_FIELDS:
        if rowmap.get(d) is True:
            leave_counts[d]+=1
work_counts={d: len(employees)-leave_counts[d] for d in DATE_FIELDS}

print(json.dumps({
    'employees_total': len(employees),
    'existing_before': len(existing),
    'created_missing': len(missing),
    'final_record_total': name_count,
    'final_fields': [f['name'] for f in final_fields['data']['fields']],
    'leave_counts': leave_counts,
    'work_counts': work_counts
}, ensure_ascii=False, indent=2))"}

