function.arguments:
{"code":"from hermes_tools import terminal
import json
BASE='QPzQbdDZLasm2vsqeFql0RPsgyg'
TABLE='tblBCgxj19VHYKFE'
r=terminal(f"lark-cli base +record-list --as user --base-token {BASE} --table-id {TABLE} --limit 200", timeout=240)
obj=json.loads(r['output'])
fields=obj['data']['fields']
rows=obj['data']['data']
counts={d:0 for d in ['26/4','27/4','30/4','1/5','2/5','3/5']}
for row in rows:
    m=dict(zip(fields,row))
    for d in counts:
        if m.get(d) is True:
            counts[d]+=1
total=len(rows)
work={d: total-counts[d] for d in counts}
print(json.dumps({'total_rows': total, 'leave_counts': counts, 'work_counts': work}, ensure_ascii=False, indent=2))"}

